def read_int(prompt):
    while True:
        raw = input(prompt)        # input() always returns a str
        try:
            return int(raw)        # may raise ValueError
        except ValueError:
            print(f"{raw!r} is not a whole number — try again.")

age = read_int("Enter your age: ")
print(f"Next year you will be {age + 1}.")

# Container conversions
print(list("abc"))          # ['a', 'b', 'c']
print(set([1, 1, 2, 3]))    # {1, 2, 3}
print(tuple(range(3)))      # (0, 1, 2)

