def classify(temp):
    if temp >= 30:
        return "hot"
    elif temp >= 15:
        return "mild"
    elif temp >= 0:
        return "cold"
    else:
        return "freezing"

print(classify(32), classify(20), classify(-5))  # hot mild freezing

# Truthiness: empty containers are falsy
items = []
if items:
    print("has items")
else:
    print("empty")            # this runs

# Ternary expression
age = 17
status = "adult" if age >= 18 else "minor"
print(status)                 # minor

