# while: repeat until a condition becomes false
countdown = 3
while countdown > 0:
    print(countdown)
    countdown -= 1
print("Liftoff!")

# break / continue
for n in range(1, 11):
    if n % 2 == 0:
        continue          # skip evens
    if n > 7:
        break             # stop entirely
    print(n, end=" ")     # 1 3 5 7
print()

# loop else: runs only if no break occurred
target = 42
for n in [10, 20, 30]:
    if n == target:
        print("found")
        break
else:
    print("not found")    # this runs
